const keyValueMap = {
  "M1D": "M04",
  "B20": "B20",
  "B21": "B21",
  "B18": "M18",
  "B19S": "V09",
  "W331": "W31",
  "W332": "W32",
  "B15D": "B05",
  "FD05": "F05",
  "HR31": "H31",
  "BY01": "C01",
  "FD02": "F02",
  "FD03": "F03",
  "W942": "W92",
  "S501": "S51",
  "W541": "W51",
  "W542": "W52",
  "R4": "W35",
  "W335": "W35"
};

const items = $input.all();

const results = items.map(item => {
  const snValue = item.json.body.sn;

  // 找出所有 key，这样 W35 会得到 ["R4", "W335"]
  const matchedKeys = Object.keys(keyValueMap).filter(key => keyValueMap[key] === snValue);

  return {
    original_sn: snValue,
    mapped_key: matchedKeys.length > 0 ? matchedKeys : null   // 无则null
  };
});

return results;

